{
    /* Check if both sensors are stale */
    if (!controller->has_valid_pressure && !controller->has_valid_door) {
        return true;
    }

    /* If we have valid pressure but it's old */
    if (controller->has_valid_pressure) {
        int64_t age = now_ms - controller->last_pressure_ms;
        if (age > threshold_ms) {
            return true;
        }
    }

    /* If we have valid door state but it's old */
    if (controller->has_valid_door) {
        int64_t age = now_ms - controller->last_door_ms;
        if (age > threshold_ms) {
            return true;
        }
    }

    return false;
